                    "type": "code"
                  }
                ],
                "text": "agents/pr-review",
                "type": "text"
              },
              {
                "text": " and pushes back where the reviewer is wrong, over-eager, or low-signal. Acts as a deliberate adversarial counter-voice (",
                "type": "text"
