                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "The doc names CODEX as the counter-model. Implement either:",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "- a different Claude model via ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "claude_args: --model ...",
                "type": "text"
              },
              {
                "text": ", OR",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- a different action / runtime if going non-Claude. Document the choice.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Stop condition",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "Cap the review/refinement back-and-forth so it cannot run forever. Options:",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "- max N rounds per PR (counter stored in a PR label or hidden HTML comment).",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "- freeze once a human posts on the PR.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "Pick one and document.",
                "type": "text"
