    "fields": {
      "summary": "Build Development Orchestrator agent (complexity gate)",
      "description": {
        "content": [
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Goal",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "Read a Jira ticket, decide complex vs. easy, and dispatch the matching dev agent (Senior or Junior).",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "Slot in the agentic workflow described in ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "docs/agentic-workflow.md",
                "type": "text"
              },
              {
                "text": " between the Ticket Agent and the dev agents.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Open question to resolve in this ticket",
                "type": "text"
              }
            ],
            "type": "heading"
          },
          {
            "content": [
              {
                "text": "How is \"complex vs. easy\" decided? Options listed in ",
                "type": "text"
              },
              {
                "marks": [
                  {
                    "type": "code"
                  }
                ],
                "text": "docs/agentic-workflow.md",
                "type": "text"
              },
              {
                "text": " §Open questions: heuristic, classifier, or LLM judgment with calibration. Pick one and document the rationale in the README.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "attrs": {
              "level": 2
            },
            "content": [
              {
                "text": "Deliverables",
                "type": "text"
